import itertools, random, math, numpy as np
def prob_ineq(coeffs,p,delta):
    B=sum(coeffs); q=1-p; T=p*(B+1)+delta
    # exact enumerate up to len maybe 20 no
    n=len(coeffs); 
    probs=0; low=0
    for mask in range(1<<n):
        s=0; k=0
        for i,c in enumerate(coeffs):
            if mask>>i &1:
                s+=c; k+=1
        pr=(p**k)*((1-p)**(n-k))
        if s >= T - 1e-12: probs += pr
        if s < T-1 - 1e-12: low += pr
    return q*probs - p*low

