def gfun(x,p):
    q=1-p
    if x >= p - 1e-12:
        return q
    elif x < -q - 1e-12:
        return -p
    else:
        return 0
def check_subharm(p):
    q=1-p
    bad=[]
    for c in np.linspace(0,1,1001):
        # breakpoints x where arguments cross -q,p and x crosses
        xs=set([-q,p, -q+p*c, p+p*c, -q-q*c, p-q*c])
        # sample intervals around range [-2,2]
        grid=np.linspace(-2,2,4001)
        for x in grid:
            lhs=q*gfun(x-p*c,p)+p*gfun(x+q*c,p)
            rhs=gfun(x,p)
            if lhs < rhs - 1e-9:
                bad.append((c,x,lhs,rhs,gfun(x-p*c,p),gfun(x+q*c,p)))
                return bad[0]
    return None
for p in [0.2,0.3,1/3,0.4]:
    print(p, check_subharm(p))

