def value_iter(p, Xmin=-3, Xmax=3, N=1201, Cgrid=None, iters=200):
    xs=np.linspace(Xmin,Xmax,N); dx=xs[1]-xs[0]; q=1-p
    V=np.array([gfun(x,p) for x in xs],float)  # can stop
    if Cgrid is None: Cgrid=np.linspace(0,1,51)
    def interp_arr(arr,y):
        # outside use g? if out of range
        return np.interp(y,xs,arr,left=gfun(y,p),right=gfun(y,p))
    for it in range(iters):
        W=V.copy()
        for c in Cgrid[1:]:
            vals=q*np.interp(xs-p*c,xs,V,left=V[0],right=V[-1])+p*np.interp(xs+q*c,xs,V,left=V[0],right=V[-1])
            W=np.minimum(W, vals)
        diff=np.max(np.abs(W-V))
        V=W
        if it%20==0: print(it,diff,V[np.argmin(abs(xs))])
        if diff<1e-6: break
    return xs,V
